import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"The Rundown AI — 2026-05-21","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-21","date":"2026-05-21T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-21-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-21-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-05/2026-05-21-the-rundown-ai.md"};function i(s,e,m,u,l,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-21" tabindex="-1">🗞️ The Rundown AI — 2026-05-21 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-21" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-21&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="gemini-s-busy-agentic-day-at-google-i-o" tabindex="-1"><a href="https://www.therundown.ai/p/gemini-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini&#39;s busy agentic day at Google I/O</a> <a class="header-anchor" href="#gemini-s-busy-agentic-day-at-google-i-o" aria-label="Permalink to &quot;[Gemini&#39;s busy agentic day at Google I/O](https://www.therundown.ai/p/gemini-busy-agentic-day-at-google-i-o)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-20</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Google had a lot to show at I/O, but the theme was even cleaner than the release list: Gemini being turned into the agentic engine behind every one of Google’s products.</p><p>New launches, including Omni, Gemini 3.5 Flash, Spark, Antigravity 2.0, and a Search overhaul, point to the same strategy — making Gemini capable, fast, and cheap enough to live wherever users already are, with an agent doing the work.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Gemini’s busy agentic day at Google I/O</p></li><li><p>Anthropic lands OpenAI co-founder Andrej Karpathy</p></li><li><p>Build automated business reports with AI</p></li><li><p>Google’s smart glasses push with ‘Intelligent Eyewear’</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="google-i-o" tabindex="-1">GOOGLE I/O <a class="header-anchor" href="#google-i-o" aria-label="Permalink to &quot;GOOGLE I/O&quot;">​</a></h6><h4 id="🚀-gemini-s-busy-agentic-day-at-google-i-o" tabindex="-1">🚀 <strong><a href="https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini’s busy agentic day at Google I/O</a></strong> <a class="header-anchor" href="#🚀-gemini-s-busy-agentic-day-at-google-i-o" aria-label="Permalink to &quot;🚀 **[Gemini’s busy agentic day at Google I/O](https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Google</p><p><strong>The Rundown:</strong> Google just <a href="https://www.youtube.com/watch?v=wYSncx9zLIU&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">introduced</a> a wave of new Gemini-powered releases and features at its flagship I/O event, including a new Omni model, 3.5 Flash, Spark agent, Antigravity 2.0, and new agentic Search upgrades.</p><p><strong>The details:</strong></p><ul><li><p>Gemini Omni can <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-omni/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">turn</a> text, images, audio, or video inputs into video outputs, with Google describing the model as “Nano Banana for video”.</p></li><li><p>The Gemini 3.5 family <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-5/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">kicks off</a> with Flash, which nears rivals like Opus 4.7 and GPT-5.5 across a variety of benchmarks at 4x the speed and half the cost.</p></li><li><p>Gemini Spark is a new 24/7 personal <a href="https://blog.google/innovation-and-ai/products/gemini-app/next-evolution-gemini-app/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">agent</a> that runs on Google Cloud virtual machines to take agentic actions across Workspace, Chrome, email, and chat.</p></li><li><p>Google framed Search&#39;s update as its biggest redesign in a generation, <a href="https://blog.google/products-and-platforms/products/search/search-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">adding</a> cross-modal inputs, 24/7 info agents, and generative UI for custom layouts.</p></li><li><p>Other features and tools included <a href="https://blog.google/innovation-and-ai/technology/research/gemini-for-science-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini for Science</a>, <a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Intelligent Eyewear</a> (more below), <a href="https://blog.google/innovation-and-ai/models-and-research/google-deepmind/project-genie-expands/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Street View simulations,</a> <a href="https://blog.google/innovation-and-ai/products/identifying-ai-generated-media-online/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">SynthID</a> AI watermarking, and more.</p></li></ul><p><strong>Why it matters:</strong> The biggest theme across these upgrades: a more agentic, multimodal Gemini getting integrated across Google’s suite in a big way. Their 3.5 Flash benchmarks don’t blow the competition away, but combining fast, cheap near-frontier capabilities with the normie-friendly tools millions of users already live in is powerful.</p><h6 id="together-with-datadog" tabindex="-1">TOGETHER WITH DATADOG <a class="header-anchor" href="#together-with-datadog" aria-label="Permalink to &quot;TOGETHER WITH DATADOG&quot;">​</a></h6><h4 id="🚀-ship-faster-with-less-guessing" tabindex="-1">🚀 <strong><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer">Ship Faster with Less Guessing</a></strong> <a class="header-anchor" href="#🚀-ship-faster-with-less-guessing" aria-label="Permalink to &quot;🚀 **[Ship Faster with Less Guessing](https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026)**&quot;">​</a></h4><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Datadog LLM Observability gives teams end-to-end visibility into their LLM applications, from prompts and tool calls to infrastructure performance and cost, so production AI systems stay reliable, secure, and worth the investment.</p><p><strong>With Datadog, you can:</strong></p><ul><li><p>Debug multi-step AI workflows before they become incidents</p></li><li><p>Monitor quality and catch regressions across model versions</p></li><li><p>Secure LLM pipelines against prompt injection and data risks</p></li></ul><p><a href="https://www.datadoghq.com/resources/llm-observability-best-practices/?utm_source=freemanforrest&amp;utm_medium=influencer&amp;utm_campaign=int-infra-ww-llm-llm-observability-therundown-052026" target="_blank" rel="noreferrer">Download the LLM Observability Best Practices Guide</a>.</p><h6 id="anthropic" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="🚪-anthropic-lands-openai-co-founder-andrej-karpathy" tabindex="-1">🚪 <strong><a href="https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Anthropic lands OpenAI co-founder Andrej Karpathy</a></strong> <a class="header-anchor" href="#🚪-anthropic-lands-openai-co-founder-andrej-karpathy" aria-label="Permalink to &quot;🚪 **[Anthropic lands OpenAI co-founder Andrej Karpathy](https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @Karpathy on X</p><p><strong>The Rundown:</strong> OpenAI co-founder and famed AI researcher Andrej Karpathy just <a href="https://x.com/karpathy/status/2056753169888334312?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">announced</a> that he has joined Anthropic, reportedly working to create an internal group focused on automating the AI training pipeline with Claude.</p><p><strong>The details:</strong></p><ul><li><p>Karpathy helped co-found OpenAI in 2015, led Tesla&#39;s Autopilot until 2022, briefly returned to OAI, and then left in 2024 to start an AI education startup.</p></li><li><p>Karpathy is joining the pre-training team under Nick Joseph and will also lead the new internal effort to apply Claude to Anthropic&#39;s own training pipeline.</p></li><li><p>&quot;The next few years at the frontier of LLMs will be especially formative,&quot; Karpathy wrote on X, adding he plans to resume his education work &quot;in time.&quot;</p></li></ul><p><strong>Why it matters:</strong> This is a massive get for Anthropic. Karpathy is one of the most respected AI researchers in the world, and luring him back to the frontier after leaving OAI (again) is notable. What’s also notable is what he’s doing there, pushing forward on the same self-building model quest we’ve seen throughout the industry this year.</p><h6 id="ai-training" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="📈-build-automated-business-reports-with-ai" tabindex="-1">📈 <strong><a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Build automated business reports with AI</a></strong> <a class="header-anchor" href="#📈-build-automated-business-reports-with-ai" aria-label="Permalink to &quot;📈 **[Build automated business reports with AI](https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to connect Codex (or Claude Code) to Google Analytics using a free tool called Composio. You will use simple prompts to explore your data and build a Markdown report that you can schedule to run weekly.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a <a href="https://composio.dev/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Composio</a> account, connect the <a href="https://dashboard.composio.dev/billy_workspace/~/connect/apps/google_analytics?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Google Analytics toolkit</a>, open Codex in Terminal, and copy and paste your custom install script from <a href="https://dashboard.composio.dev/billy_workspace/~/connect/clients/codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">here</a></p></li><li><p>In Codex, prompt: “Use the Composio CLI tool to inspect our Google Analytics setup. Identify the available accounts and properties, find the property that tracks [SITE_OR_APP], and tell me which dimensions and metrics you would use for a useful traffic report. Do not create the report yet”</p></li><li><p>Once reviewed, prompt: “Use Composio + GA to identify the three most important trends over the last 90 days. Return a markdown report with an executive summary, tables, source notes, and recommended actions”</p></li><li><p>Tell Codex to visualize the report as a PDF/website, and finally turn the steps into reusable skills, with an automation to run those skills daily/weekly/monthly</p></li></ol><p><strong>Pro tip:</strong> Ask Codex to audit the Composio toolkit for useful connections. Use the Explore, Analyze, Visualize framework on other connectors like YouTube or Shopify.</p><h6 id="presented-by-fiddler" tabindex="-1">PRESENTED BY FIDDLER <a class="header-anchor" href="#presented-by-fiddler" aria-label="Permalink to &quot;PRESENTED BY FIDDLER&quot;">​</a></h6><h4 id="🧮-run-the-math-on-your-ai-evals-tco" tabindex="-1">🧮 <a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer"><strong>Run the math on your AI evals TCO</strong></a> <a class="header-anchor" href="#🧮-run-the-math-on-your-ai-evals-tco" aria-label="Permalink to &quot;🧮 [**Run the math on your AI evals TCO**](https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco)&quot;">​</a></h4><p><a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> External LLM evaluation charges you per API call and increases as you scale. If you try to control spend with reduced sampling, you risk incidents slipping through undetected. Fiddler Centor Models run evals in your own infrastructure with no per-call costs, reducing your evaluation Total Cost of Ownership as you scale.</p><p><strong>Put in your numbers to see:</strong></p><ul><li><p>Your annual eval cost across GPT, Claude, and Gemini models at your trace volume</p></li><li><p>How each evaluator you add increases your per-trace spend</p></li><li><p>How your evaluation costs curves shift as agent traffic grows</p></li></ul><p><a href="https://www.fiddler.ai/evals-tco-calculator?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=evals-tco" target="_blank" rel="noreferrer">Calculate my evaluation TCO</a>.</p><h6 id="google" tabindex="-1">GOOGLE <a class="header-anchor" href="#google" aria-label="Permalink to &quot;GOOGLE&quot;">​</a></h6><h4 id="👓-google-s-smart-glasses-push-with-intelligent-eyewear" tabindex="-1">👓 <strong><a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Google’s smart glasses push with ‘Intelligent Eyewear’</a></strong> <a class="header-anchor" href="#👓-google-s-smart-glasses-push-with-intelligent-eyewear" aria-label="Permalink to &quot;👓 **[Google’s smart glasses push with ‘Intelligent Eyewear’](https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h4><p>Image source: Google</p><p><strong>The Rundown:</strong> Google just provided a <a href="https://blog.google/products-and-platforms/platforms/android/android-xr-io-2026/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">teaser</a> of its Intelligent Eyewear Gemini-powered smart glasses, partnering with Warby Parker and Gentle Monster on voice-first AI frames shipping this fall, and a display-equipped Project Aura to follow.</p><p><strong>The details:</strong></p><ul><li><p>The audio frames pair with Android or iOS phones, running Gemini for voice, navigation, messaging, photos with Nano Banana editing, and live translation.</p></li><li><p>The glasses will feature cameras, mics, over-ear speakers, and Gemini access through &quot;Hey Google&quot; or a tap on the frame for quick help.</p></li><li><p>The lineup is Google&#39;s first glasses push since Google Glass folded, with Samsung on hardware and Gentle Monster and Warby Parker handling frames.</p></li><li><p>XReal’s Android XR ‘<a href="https://www.xreal.com/us/aura?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Project Aura</a>’ display glasses are farther away, which will allow users to see videos or content for interactive experiences.</p></li></ul><p><strong>Why it matters:</strong> Google’s Meta Ray-Ban competitor is officially coming, and its first iteration is a light one — with the audio-first frames coming in a step behind their rival’s already screen-equipped options. But the allure of the Google and Gemini ecosystem can definitely be the stickier option for consumers to tie their AI-powered life together.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><ul><li><p>📱 <a href="https://www.metabind.ai?utm_source=rundown&amp;utm_medium=newsletter&amp;utm_campaign=rundown_ai_may2026" target="_blank" rel="noreferrer">Metabind</a> - Build native MCP Apps with interactive UI. One click to ChatGPT, Claude, or your iOS/Android AI Assistant*</p></li><li><p>🧠 <a href="http://www.rundown.ai/tools/gemini-3-5-flash?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini 3.5 Flash</a> - Google&#39;s new flash model, 4x faster at half price</p></li><li><p>🤖 <a href="http://www.rundown.ai/tools/gemini-spark?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini Spark</a> - Google&#39;s personal agent that runs 24/7 on Cloud VMs</p></li><li><p>🎥 <a href="https://www.rundown.ai/tools/gemini-omni?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Gemini Omni Flash</a> - Google&#39;s multimodal video model that edits via chat</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><p><strong>New reporting</strong> <a href="https://www.ft.com/content/8f2a529e-7a1b-4d8e-95be-338d0c4c98f5?syn-25a6b1a6=1&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">revealed</a> that Google Deepmind’s Demis Hassabis was an early angel investor in Anthropic, with Google also separately investing billions in the AI rival.</p><p><strong>Anthropic</strong><a href="https://claude.com/blog/claude-managed-agents-updates?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">rolled out</a> sandboxes and MCP tunnels to Claude Managed Agents, letting teams run tool execution and reach internal servers without exposing them publicly.</p><p><strong>METR</strong> <a href="https://x.com/METR_Evals/status/2056800023149760666?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">published</a> its first Frontier Risk Report, finding agents from top labs can autonomously finish multi-week engineering work, but struggle on hard-to-verify tasks.</p><p><strong>OpenAI</strong> is <a href="https://openai.com/index/advancing-content-provenance/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">adopting</a> Google&#39;s SynthID watermarking for ChatGPT images, alongside a public verification tool that detects whether an image came from its models.</p><p><strong>Google and Blackstone</strong> <a href="https://www.blackstone.com/news/press/blackstone-announces-joint-venture-with-google-to-create-new-tpu-cloud/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">formed</a> a joint AI cloud venture to rent out Google&#39;s TPU chips, with the PE giant&#39;s $5B investment marking a deep push into AI infrastructure.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Anonymous:</strong></p><p>&quot;I occasionally see a ‘sponsored’ ad on Facebook that intrigues me to look. After reading through pages and pages exhorting the over-the-top values of the item and further pages of testimonials, the price eventually shows up IF I believe 1/2 the pomp and circumstance.</p><p>I had the wild idea of feeding the link to my AI preceded by &quot;Is this a scam?&quot; and I get a detailed yes, no, maybe with details, background, and usually an &quot;avoid this and go to &#39;other website/store&#39; and check out the same item&quot;.</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/musk-openai-case-runs-out-of-time?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">OpenAI beats Musk on the clock</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/meta-cyborg-smart-glasses-for-soldiers?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Meta’s cyborg smart glasses for soldiers</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-humanoid-bingewatch-is-still-ongoing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Figure’s humanoid bingewatch continues</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/build-automated-business-reports-with-ai-works-with-google-analytics-youtube-shopify-and-more?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Build automated business reports with AI</a></p></li><li><p>RSVP to next workshop on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=gemini-s-busy-agentic-day-at-google-i-o" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="musk-s-openai-case-runs-out-of-time" tabindex="-1"><a href="https://www.therundown.ai/p/musk-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Musk&#39;s OpenAI case runs out of time</a> <a class="header-anchor" href="#musk-s-openai-case-runs-out-of-time" aria-label="Permalink to &quot;[Musk&#39;s OpenAI case runs out of time](https://www.therundown.ai/p/musk-openai-case-runs-out-of-time)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-19</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Advertise</a></strong></p><p>[](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</p><p><strong>Good morning, AI enthusiasts.</strong> Three weeks of high-profile testimonies, spicy leaked messages, and $100B in claims made for a blockbuster trial — but Elon Musk vs. OpenAI’s conclusion didn’t live up to the hype.</p><p>With jurors dismissing the suit in OpenAI’s favor and Musk calling the ruling a “calendar technicality” and vowing to appeal, a more dramatic conclusion to the massive tech trial may have to wait for another day in court.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Elon Musk loses lawsuit against OpenAI, Microsoft</p></li><li><p>Cursor’s Composer 2.5 nears coding frontier</p></li><li><p>3D model anything with Claude and Blender</p></li><li><p>Odyssey’s multimodal, multiplayer world models</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="elon-musk-vs-openai" tabindex="-1">ELON MUSK VS. OPENAI <a class="header-anchor" href="#elon-musk-vs-openai" aria-label="Permalink to &quot;ELON MUSK VS. OPENAI&quot;">​</a></h6><h4 id="👨🏻‍⚖️-elon-musk-loses-lawsuit-against-openai-microsoft" tabindex="-1">👨🏻‍⚖️ <a href="https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer"><strong>Elon Musk loses lawsuit against OpenAI, Microsoft</strong></a> <a class="header-anchor" href="#👨🏻‍⚖️-elon-musk-loses-lawsuit-against-openai-microsoft" aria-label="Permalink to &quot;👨🏻‍⚖️ [**Elon Musk loses lawsuit against OpenAI, Microsoft**](https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @ElonMusk on X</p><p><strong>The Rundown:</strong> Elon Musk’s $100B+ lawsuit against OpenAI, Sam Altman, Greg Brockman, and Microsoft was just <a href="https://www.cnn.com/2026/05/18/tech/openai-musk-lawsuit-verdict?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">dismissed</a> after a high-profile three-week trial, with the jury unanimously finding that the case was filed years too late.</p><p><strong>The details:</strong></p><ul><li><p>The lawsuit alleged that Altman and Brockman &#39;stole a charity&#39; by shifting OAI to for-profit, but the jury felt that Musk knew for years before suing.</p></li><li><p>OAI&#39;s attorneys had argued that Musk backed a for-profit structure himself, pushed for control, and only sued after starting his own AI rival xAI in 2023.</p></li><li><p>Musk’s Microsoft claim was also dismissed, after he had accused the company of aiding OpenAI through its multibillion-dollar backing.</p></li><li><p>Musk <a href="https://x.com/elonmusk/status/2056474896641782077?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">posted</a> on X that the jury’s ruling wasn’t on “the merits of the case, just on a calendar technicality” and that he will be appealing the decision.</p></li></ul><p><strong>Why it matters:</strong> The blockbuster trial, packed with private texts and billionaire testimony, did not end with a bang but with a quick dismissal due to the legal clock. It’s a big win for OAI, but an unsatisfying one for anyone hoping the case would settle the question of who controls a nonprofit AI giant once billions of dollars enter the picture.</p><h6 id="together-with-you-com" tabindex="-1">TOGETHER WITH YOU.COM <a class="header-anchor" href="#together-with-you-com" aria-label="Permalink to &quot;TOGETHER WITH YOU.COM&quot;">​</a></h6><h4 id="⚖️-don-t-put-all-your-api-eggs-in-the-latency-basket-https-you-com-resources-why-api-latency-alone-is-a-misleading-metric-download-utm-campaign-28104480-the-rundown-q4-utm-source-external-newsletter-utm-medium-email-utm-term-rundown-primary-5-19-26-utm-content-rundown-primary-5-19-26" tabindex="-1">⚖️ <strong>[Don’t put all your API eggs in the latency basket](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</strong> <a class="header-anchor" href="#⚖️-don-t-put-all-your-api-eggs-in-the-latency-basket-https-you-com-resources-why-api-latency-alone-is-a-misleading-metric-download-utm-campaign-28104480-the-rundown-q4-utm-source-external-newsletter-utm-medium-email-utm-term-rundown-primary-5-19-26-utm-content-rundown-primary-5-19-26" aria-label="Permalink to &quot;⚖️ **[Don’t put all your API eggs in the latency basket](https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)**&quot;">​</a></h4><p>[](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26)</p><p><strong>The Rundown:</strong> Picking an API by scanning a benchmark table and calling it done is a shortcut that can obscure what actually matters in production—like accuracy. This guide from [You.com](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26) breaks down why raw latency is a deceptive signal and why accuracy, along with other real-world metrics, is what you should be measuring instead.</p><p><strong>What you&#39;ll learn:</strong></p><ul><li><p>Why p50 latency hides the failures your users actually experience</p></li><li><p>The &quot;time-to-useful-result&quot; framework that captures what benchmarks leave out</p></li><li><p>Four hidden cost drivers that show up in your logs, not vendor tables</p></li><li><p>How to evaluate APIs at your actual concurrency levels, not the demo conditions</p></li></ul><p>[Download the guide](<a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.19.26&amp;utm_content=rundown_primary_5.19.26).</p><h6 id="cursor" tabindex="-1">CURSOR <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;CURSOR&quot;">​</a></h6><h4 id="⚙️-cursor-s-composer-2-5-efficiently-coding-frontier" tabindex="-1">⚙️ <strong><a href="https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Cursor’s Composer 2.5 efficiently coding frontier</a></strong> <a class="header-anchor" href="#⚙️-cursor-s-composer-2-5-efficiently-coding-frontier" aria-label="Permalink to &quot;⚙️ **[Cursor’s Composer 2.5 efficiently coding frontier](https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p>Image source: Cursor</p><p><strong>The Rundown:</strong> Cursor just <a href="https://cursor.com/blog/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">released</a> Composer 2.5, the company’s upgraded in-house coding model built on Moonshot’s Kimi K2.5, showing near-frontier benchmark performance at much lower token prices.</p><p><strong>The details:</strong></p><ul><li><p>Composer 2.5 nears Anthropic’s 4.7 and OAI’s GPT 5.5 across top development benchmarks, while showing a nearly 10% step up from its predecessor.</p></li><li><p>An average CursorBench task costs under $1 with Composer 2.5, compared to up to $11 per task for Opus 4.7 and GPT-5.5 at similar score levels.</p></li><li><p>Composer 2.5 <a href="https://x.com/elonmusk/status/2056422097237283295?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">was</a> “partially trained on Colossus 2”, with Cursor also <a href="https://x.com/cursor_ai/status/2056415419536461836?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">revealing</a> it is currently training a larger SpaceXAI model with 10x more compute.</p></li></ul><p><strong>Why it matters:</strong> Months back, Composer 2 was swinging at the frontier at 1/10th the cost of GPT-5.4. Composer 2.5 picks up that thread, this time landing Opus 4.7-class scores while staying under $1 per task. With xAI’s Colossus compute muscle now fully behind Cursor, its next model could be the one that takes over the frontier.</p><h6 id="ai-training-1" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-1" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🧊-3d-model-anything-with-claude-and-blender" tabindex="-1">🧊 <strong><a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">3D model anything with Claude and Blender</a></strong> <a class="header-anchor" href="#🧊-3d-model-anything-with-claude-and-blender" aria-label="Permalink to &quot;🧊 **[3D model anything with Claude and Blender](https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to connect Blender to Claude Code with MCP, then use plain English to create and edit a 3D scene.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Download and install <a href="https://blender.org?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Blender</a> as well as its <a href="https://www.blender.org/lab/mcp-server/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">MCP extension</a>. Once done, Open Edit &gt; Preferences in Blender, search MCP, and enable the extension</p></li><li><p>In Terminal, open Claude Code in your project folder and connect Blender with: “claude mcp add blender -- uvx blender-mcp-server claude mcp get blender”</p></li><li><p>Ask Claude to verify the setup with: “Connect Claude Code to Blender and make sure my mcp.json or Claude MCP config is set up correctly. Check Blender is running MCP server, confirm the host and port, register Blender, and verify the connection before editing&quot;</p></li><li><p>Test with: ”Use Blender MCP to model my name in 3D. Add disco balls and lighting, reflective materials, and a camera angle to make it like an event poster”</p></li></ol><p><strong>Pro tip:</strong> Once connected, download models from sites like <a href="https://www.blenderkit.com/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">BlenderKit</a>, open them in Blender, and ask Claude to arrange objects, adjust lighting, and prepare a render.</p><h6 id="presented-by-lightfield" tabindex="-1">PRESENTED BY LIGHTFIELD <a class="header-anchor" href="#presented-by-lightfield" aria-label="Permalink to &quot;PRESENTED BY LIGHTFIELD&quot;">​</a></h6><h4 id="🤖-outbound-agents-that-run-on-your-crm" tabindex="-1">🤖****<a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer"><strong>Outbound agents that run on your CRM</strong></a> <a class="header-anchor" href="#🤖-outbound-agents-that-run-on-your-crm" aria-label="Permalink to &quot;🤖****[**Outbound agents that run on your CRM**](https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026)&quot;">​</a></h4><p><a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Lightfield is the AI CRM with agents that prospect for you. They find companies that look like your fastest-growing customers and engage them with messaging that’s proven to work from your previously won deals.</p><p><strong>In Lightfield, you can:</strong></p><ul><li><p>Score accounts on fit, signals, and mutual connections</p></li><li><p>Run email and LinkedIn sequences in your customers&#39; words</p></li><li><p>Refresh your target list based on what works</p></li></ul><p><a href="https://lightfield.app/product/ai-pipeline-generation?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=rundown&amp;utm_content=secondary_5-19-2026" target="_blank" rel="noreferrer">See how it works</a>.</p><h6 id="odyssey" tabindex="-1">ODYSSEY <a class="header-anchor" href="#odyssey" aria-label="Permalink to &quot;ODYSSEY&quot;">​</a></h6><h4 id="🌎-odyssey-s-multimodal-multiplayer-world-models" tabindex="-1">🌎 <strong><a href="https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Odyssey’s multimodal, multiplayer world models</a></strong> <a class="header-anchor" href="#🌎-odyssey-s-multimodal-multiplayer-world-models" aria-label="Permalink to &quot;🌎 **[Odyssey’s multimodal, multiplayer world models](https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h4><p>Image source: Odyssey</p><p><strong>The Rundown:</strong> Odyssey just <a href="https://odyssey.ml/introducing-starchild-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">marked</a> two world model firsts back-to-back, dropping Starchild-1, which the company calls the first real-time, multimodal world model, and <a href="https://odyssey.ml/introducing-agora-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Agora-1</a>, which lets multiple players interact inside the same AI-generated world.</p><p><strong>The details:</strong></p><ul><li><p>Starchild-1 can generate synchronized audio and video on the fly while taking in and adjusting to user inputs, with no fixed generation length.</p></li><li><p>Agora-1 can host up to 4 players in one AI-generated world stream, demoed via a GoldenEye video game simulation where every pixel is produced live.</p></li><li><p>Agora keeps a shared game state across participants, tracking agent details like position and health as actions change the world.</p></li><li><p>The company frames Agora as an early preview for multiplayer games, robotics, and agents training together inside simulations.</p></li></ul><p><strong>Why it matters:</strong> Many of the sharpest minds in tech believe world models are the future of the industry, and these previews look like a major move up the capability ladder. Going from rendered clips to live, adjustable shared streams opens whole new avenues for both creative (gaming, storytelling) and simulation (robotics, AI training).</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-1" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-1" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><ul><li><p>🐳 <a href="https://www.triplewhale.com/moby-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Moby 2</a> - The AI ecommerce operator brands trust to run Meta ads, build Klaviyo campaigns, and generate creatives that actually work*</p></li><li><p>⚙️ <a href="https://www.rundown.ai/tools/composer-2-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Composer 2.5</a> - Cursor&#39;s near-frontier and efficient in-house coding model</p></li><li><p>🎆 <a href="https://www.rundown.ai/tools/krea-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Krea 2</a> - Krea’s first in-house image model, now generally available</p></li><li><p>🧑‍💻 <a href="https://x.com/cognition/status/2056396941181727210?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Devin</a> - New Auto-Triage coding security feature with long-term memory</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-1" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-1" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><p><strong>Anthropic</strong> <a href="https://www.anthropic.com/news/anthropic-acquires-stainless?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">acquired</a> Stainless, the startup behind its official SDKs and MCP server tooling, adding the team previously responsible for Claude&#39;s developer libraries.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/malta-chatgpt-plus-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">partnered</a> with Malta to offer free ChatGPT Plus to every citizen who completes a national AI literacy course, the first country-wide deal of its kind.</p><p><strong>Amazon</strong><a href="https://www.aboutamazon.com/news/devices/alexa-podcasts-ai-generated-audio-episodes?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">rolled out</a> Alexa Podcasts, a new NotebookLM-style custom podcast creator in Alexa+ that creates a conversation between two AI hosts on any topic.</p><p><strong>Meta</strong> is <a href="https://www.cnbc.com/2026/05/18/metas-layoffs-starting-this-week-underscore-zuckerbergs-ai-reality-.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">laying off</a> as many as 8,000 employees this week and is no longer planning to hire for another 6,000 open roles, coming as part of the company’s AI efficiency push.</p><p><strong>OpenAI</strong> <a href="https://openai.com/index/dell-codex-enterprise-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">announced</a> a new partnership with Dell to run Codex inside corporate data centers, connecting the coding agent to enterprise internal systems.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-1" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-1" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Michael D.</strong> in Littleton, CO:</p><p>“I teach mindfulness and meditation. I&#39;m not a master - just someone in the middle of a long path with several years of serious practice and a pile of small wins, stumbles, and reframings that tend to be relatable for newer students.</p><p>Over those years, my notes accumulated everywhere—Gmail, OneNote, Word, paper, the Notes app—none of it organized, most of it &quot;somewhere else&quot; when I actually wanted it. A few weeks ago I started moving all of it into Obsidian as markdown files, each tagged with metadata: title, date, themes, teaching potential, and free-form notes.</p><p>Now that Claude is pointed at my Obsidian vault in Claude Cowork, it can pull in my own reflections, the stories I&#39;ve actually lived, and the quotes I&#39;ve actually saved. Students get a teaching grounded in real practice rather than a generic synthesis.</p><p>The unexpected payoff is for my own practice. Claude sometimes uses my notes in ways I wouldn&#39;t have thought of, and I end up with a new perspective on my own experience that I didn&#39;t even plan for.”</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-1" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-1" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/ai-anger-comes-for-claude-monet?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">AI anger comes for Claude (Monet)</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/space-pharma-gets-serious?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Space pharma gets serious</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-humanoid-bingewatch-is-still-ongoing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Figure’s humanoid bingewatch continues</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-3d-model-anything-with-claude-blender?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">3D model anything with Claude and Blender</a></p></li><li><p>RSVP to our next free live session on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=musk-s-openai-case-runs-out-of-time" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="ai-anger-comes-for-claude-monet" tabindex="-1"><a href="https://www.therundown.ai/p/ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">AI anger comes for Claude (Monet)</a> <a class="header-anchor" href="#ai-anger-comes-for-claude-monet" aria-label="Permalink to &quot;[AI anger comes for Claude (Monet)](https://www.therundown.ai/p/ai-anger-comes-for-claude-monet)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-18</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Thousands of people on X just confidently explained why an AI-generated image was inferior to a real Monet. Just one problem: It WAS a real Monet.</p><p>Conceptual artist SHL0MS’ latest experiment says less about AI art and more about the reflexive hostility baked into the tech, with critics lining up to trash an artwork the moment they thought a machine made it.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Artist shines mirror on AI anger with Monet post</p></li><li><p>The Rundown Roundtable: Our AI use cases</p></li><li><p>Build your cloud-based web crawler with Manus</p></li><li><p>ChatGPT starts connecting to your money</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="ai-art-anger" tabindex="-1">AI, ART &amp; ANGER <a class="header-anchor" href="#ai-art-anger" aria-label="Permalink to &quot;AI, ART &amp; ANGER&quot;">​</a></h6><h4 id="🖼️-artist-shines-mirror-on-ai-anger-with-viral-monet-post" tabindex="-1">🖼️ <strong><a href="https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Artist shines mirror on AI anger with viral Monet post</a></strong> <a class="header-anchor" href="#🖼️-artist-shines-mirror-on-ai-anger-with-viral-monet-post" aria-label="Permalink to &quot;🖼️ **[Artist shines mirror on AI anger with viral Monet post](https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown / @SHL0MS on X</p><p><strong>The Rundown:</strong> Artist SHL0MS <a href="https://x.com/TheRundownAI/status/2054942919367197112?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">sparked</a> a frenzy on X over a post that presented a real image of a painting from famed impressionist Claude Monet as AI-generated, sparking critiques of the work and shining a mirror on anti-AI bias seen in the creative world.</p><p><strong>The details:</strong></p><ul><li><p>SHL0MS <a href="https://x.com/SHL0MS/status/2054280631807316329?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">posted</a> that he generated the image in the style of Monet, asking users to describe why the &quot;AI image&quot; is inferior in as much detail as possible.</p></li><li><p>The post received thousands of responses calling the image ‘emotionless’, ‘slop’, and critiquing specific features like depth, reflections, and composition.</p></li><li><p>The image was an <a href="https://en.wikipedia.org/wiki/File:Nympheas_71293_3.jpg?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">image</a> of a real Monet, identified as from his Water Lilies collection from around 1915.</p></li><li><p>The saga aligns with 2024 <a href="https://www.nature.com/articles/s41598-024-54294-4?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">research</a>, with Norwegian researchers finding people actually prefer AI art but show a clear negative bias against it.</p></li></ul><p><strong>Why it matters:</strong> This Monet-gate was one painting, but the reflex it exposed runs through the entire creative world right now. For a growing crowd, the word &#39;AI&#39; alone triggers backlash regardless of context — and that knee-jerk hostility is only growing as the tech changes the world around us and embeds deeper into everyday life.</p><h6 id="together-with-unwrap" tabindex="-1">TOGETHER WITH UNWRAP <a class="header-anchor" href="#together-with-unwrap" aria-label="Permalink to &quot;TOGETHER WITH UNWRAP&quot;">​</a></h6><h4 id="⚡-see-how-oura-automates-customer-feedback-analysis" tabindex="-1">⚡ <strong><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">See how Oura automates customer feedback analysis</a></strong> <a class="header-anchor" href="#⚡-see-how-oura-automates-customer-feedback-analysis" aria-label="Permalink to &quot;⚡ **[See how Oura automates customer feedback analysis](https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Unwrap’s customer intelligence platform pulls all your feedback (surveys, reviews, support tickets, social comments, etc.) into one view, then uses AI + NLP to surface the most actionable insights straight to your inbox. Teams at Perplexity, Oura, Stripe, lululemon and DoorDash rely on Unwrap to ensure no customer voice gets lost.</p><p><strong>With Unwrap, you get:</strong></p><ul><li><p>All customer feedback automatically categorized</p></li><li><p>Query feedback using Unwrap Assistant, or in your favorite tools using Unwrap&#39;s MCP</p></li><li><p>Real-time alerts from feedback and a clear view of customer sentiment</p></li><li><p>New, out-of-the-box AI surveys with dynamic follow-up</p></li></ul><p>Unwrap is offering free trials to Rundown AI subscribers — <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">grab 15 minutes with the team to get set up</a>.</p><h6 id="the-rundown-roundtable" tabindex="-1">THE RUNDOWN ROUNDTABLE <a class="header-anchor" href="#the-rundown-roundtable" aria-label="Permalink to &quot;THE RUNDOWN ROUNDTABLE&quot;">​</a></h6><h4 id="💡-the-rundown-roundtable-our-ai-use-cases" tabindex="-1">💡 <strong><a href="http://www.rundown.ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">The Rundown Roundtable: Our AI use cases</a></strong> <a class="header-anchor" href="#💡-the-rundown-roundtable-our-ai-use-cases" aria-label="Permalink to &quot;💡 **[The Rundown Roundtable: Our AI use cases](http://www.rundown.ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: Ideogram / The Rundown</p><p><strong>The Rundown:</strong> The Rundown Roundtable is a weekly feature where we poll members of The Rundown staff about how we use AI in our work and daily lives.</p><p><strong>Billy, University Educator:</strong> I made Claude Code my apprentice CAD designer because I don&#39;t know anything about engineering.</p><p>My wife needed a ring container to attach to her water bottle at the gym. I drew my idea for a threaded container and told Claude to prototype it. The first few prints were rough. But after the 8th prototype, we had the perfect design.</p><p><strong>Rishi, Growth:</strong> YouTube is one of the best free education platforms out there, but the problem is that it takes a ton of time to sit through long videos just to find the few ideas that actually matter.</p><p>That’s where Gemini has been really useful for me. Since it’s built into Google, I can use it to quickly summarize a specific YouTube video, or even scan the last 5–10 videos from a creator to pull out the key takeaways.</p><p>Instead of spending hours watching everything, I can quickly understand the main ideas, find the best nuggets, and decide what’s worth digging into deeper. It’s basically a shortcut for learning from long-form content without consuming every minute of it.</p><h6 id="ai-training-2" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-2" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="☁️-build-your-cloud-based-web-crawler-with-manus" tabindex="-1">☁️ <a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"><strong>Build your cloud-based web crawler with Manus</strong></a> <a class="header-anchor" href="#☁️-build-your-cloud-based-web-crawler-with-manus" aria-label="Permalink to &quot;☁️ [**Build your cloud-based web crawler with Manus**](https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to turn <a href="https://manus.im/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Manus</a> Cloud Computer into a private 24/7 web crawler for any site you want to monitor. Instead of having Manus burn tokens checking the same site each day, your cloud computer does it for cheap.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Open the Manus desktop app, go to Settings &gt; My Computer, and click Create now under Cloud Computer to give Manus an always-on server</p></li><li><p>Start a new Manus task, select your Cloud Computer in the composer</p></li><li><p>Prompt: Set up a web crawler on my Cloud Computer for [URL]. First, inspect the site formatting and tell me the best way to check it reliably. Check for [info] twice a day. Log it to a CSV. Create a small script, schedule it with cron, log every run, and only save results that match [criteria]</p></li><li><p>Have Manus run the script once, then run it on 24/7. Once done, you can have Manus check the collected data anytime from your phone or laptop</p></li></ol><p><strong>Going further:</strong> Start with a Manus/Claude skill, or any AI workflow you use. Ask Manus which repetitive parts can run &quot;for free&quot; on your cloud computer, then save the agent.</p><h6 id="presented-by-function-health" tabindex="-1">PRESENTED BY FUNCTION HEALTH <a class="header-anchor" href="#presented-by-function-health" aria-label="Permalink to &quot;PRESENTED BY FUNCTION HEALTH&quot;">​</a></h6><h4 id="🩺-your-body-has-receipts" tabindex="-1">🩺 <a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"><strong>Your body has receipts</strong></a> <a class="header-anchor" href="#🩺-your-body-has-receipts" aria-label="Permalink to &quot;🩺 [**Your body has receipts**](https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h4><p><a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Function gives you access to 160+ lab tests, personalized insights, and ongoing tracking in one place — so you can see what&#39;s happening inside your body before symptoms show up.</p><p><strong>A Function membership gives you:</strong></p><ul><li><p>160+ lab tests run annually across key health markers</p></li><li><p>Private AI Chat trained on your individual results</p></li><li><p>Clinician-reviewed insights to put your data in context</p></li><li><p>Continuous tracking so you can see what changes over time</p></li></ul><p><a href="https://www.functionhealth.com/tcm/the-rundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Own your health</a> and use code <strong>RUNDOWN50</strong> for $50 off your membership.</p><h6 id="openai" tabindex="-1">OPENAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="💸-chatgpt-starts-connecting-to-your-money" tabindex="-1">💸 <strong><a href="https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">ChatGPT starts connecting to your money</a></strong> <a class="header-anchor" href="#💸-chatgpt-starts-connecting-to-your-money" aria-label="Permalink to &quot;💸 **[ChatGPT starts connecting to your money](https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h4><p>Image source: OpenAI</p><p><strong>The Rundown:</strong> OpenAI <a href="https://openai.com/index/personal-finance-chatgpt?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">released</a> a new personal finance experience inside ChatGPT, partnering with Plaid to connect users’ financial institutions and give the chatbot real-time access to spending, investments, and bills for personalized financial insights.</p><p><strong>The details:</strong></p><ul><li><p>Users can connect via Plaid across Chase, Schwab, Robinhood, and 12,000+ institutions, with a dashboard tracking spending, portfolio, and upcoming bills.</p></li><li><p>Intuit support is planned next for flows like tax estimates, credit-card approval odds, and connecting users to live experts.</p></li><li><p>ChatGPT can analyze connected data, but cannot move money, pay bills, make trades, or file taxes (yet).</p></li><li><p>The feature preview starts with U.S.-based Pro accounts, accessible via a new ‘finance’ sidebar or by tagging @finance directly in chats.</p></li></ul><p><strong>Why it matters:</strong> Financial guidance has been locked behind pricy advisors or clunky apps for a decade, and having a complete view of a user’s finances as context can unlock a seriously powerful experience. The biggest hurdle might be getting users to trust AI with that information, which is where Plaid comes in as the secure layer.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-2" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-2" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><ul><li><p>💸 <a href="https://www.rundown.ai/tools/chatgpt-for-personal-finance?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">ChatGPT for Personal Finance</a> - Personal finance experience in ChatGPT</p></li><li><p>📱 <a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Codex</a> - OpenAI’s agentic platform, now available via mobile</p></li><li><p>💻 <a href="http://www.rundown.ai/tools/higgsfield-supercomputer?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Higgsfield Supercomputer</a> - Cloud AI agent with tools, memory, and more</p></li><li><p>🌌 <a href="https://www.rundown.ai/tools/krea-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Krea 2</a> - Krea&#39;s image AI with style transfer, moodboard-based generation</p></li></ul><h3 id="📰-everything-else-in-ai-today-2" tabindex="-1">📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Everything else in AI today</a> <a class="header-anchor" href="#📰-everything-else-in-ai-today-2" aria-label="Permalink to &quot;📰 [Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)&quot;">​</a></h3><p><strong>OAI’s</strong> Greg Brockman is <a href="https://www.wired.com/story/openai-reorg-greg-brockman-product/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">reportedly</a> moving to product strategy, with Thibault Sottiaux now leading core product and platform, and Nick Turley shifting to enterprise products.</p><p><strong>Anthropic</strong> <a href="https://www.anthropic.com/news/gates-foundation-partnership?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">formed</a> a $200M partnership with the Gates Foundation to deploy Claude in vaccine screening, disease forecasting, and K-12 tutoring in developing nations.</p><p><strong>OpenAI</strong> reportedly <a href="https://www.theinformation.com/briefings/openai-buys-audio-startup-weights?rc=a8sc5q&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">acquired</a> Weights.gg in January, a voice-cloning social network with celebrity replicas, with six staff members joining the company.</p><p><strong>Pope Leo XIV</strong> <a href="https://apnews.com/article/vatican-artificial-intelligence-pope-musk-nvidia-trump-889c0066f0d5ce784c07abb72b33e24c?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">established</a> a Vatican AI advisory body and signed his first encyclical, which is expected to frame the technology as this generation&#39;s Industrial Revolution.</p><p><strong>Poetiq</strong><a href="https://poetiq.ai/posts/recursive_self_improvement_coding/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">released</a> new research showing its self-building Meta-System can create and improve on its own harness, and achieve SOTA scores on a top coding benchmark.</p><p><strong>A Gallup survey</strong> <a href="https://news.gallup.com/poll/709772/americans-oppose-data-centers-area.aspx?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">found</a> that 70% of Americans oppose data centers being built nearby, with the infrastructure polling as less popular than local nuclear power plants.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-2" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-2" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Anonymous:</strong></p><p>&quot;I&#39;m learning to play guitar and kind of stuck at an advanced beginner level. I used Claude to create a practice journal to document each session - minutes practiced, chords learned, songs in progress, things to work on, that then creates a visual data dashboard of trends, song learning status, etc.</p><p>At the end of each updated dashboard, Claude gives me three to five new things to work on based on what I am practicing, similar songs to learn to take to the next level.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-2" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-2" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-takes-codex-mobile?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">OpenAI takes Codex mobile</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/space-pharma-gets-serious?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Space pharma gets serious</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meet-unitree-giant-new-mech?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Meet Unitree’s giant new mech</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/build-your-own-web-crawler-with-manus-runs-in-the-cloud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Build your own cloud-based web crawler with Manus</a></p></li><li><p>RSVP to our next free live session on May 27: <a href="https://app.therundown.ai/live/become-an-ai-native-leader?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-anger-comes-for-claude-monet" target="_blank" rel="noreferrer">Become an AI-native leader</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="openai-takes-codex-mobile" tabindex="-1"><a href="https://www.therundown.ai/p/openai-takes-codex-mobile" target="_blank" rel="noreferrer">OpenAI takes Codex mobile</a> <a class="header-anchor" href="#openai-takes-codex-mobile" aria-label="Permalink to &quot;[OpenAI takes Codex mobile](https://www.therundown.ai/p/openai-takes-codex-mobile)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-15</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> AI coding agents can now run for hours at a time. Sitting at your desk the entire time shouldn&#39;t be a requirement… Or carrying around a computer to keep things moving.</p><p>Codex going mobile inside the ChatGPT app is OpenAI&#39;s long-awaited answer to that problem, letting users approve decisions, start new tasks, and make changes from their phone while agents grind away back at the desk.</p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>OpenAI’s Codex moves beyond the desktop</p></li><li><p>OpenAI, Apple’s ‘deteriorating’ relationship</p></li><li><p>Automate marketing assets with ChatGPT Images 2.0</p></li><li><p>Anthropic angers devs with new agent credit split</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="openai-1" tabindex="-1">OPENAI <a class="header-anchor" href="#openai-1" aria-label="Permalink to &quot;OPENAI&quot;">​</a></h6><h4 id="📱-openai-scodex-moves-beyond-the-desktop" tabindex="-1">📱****<a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"><strong>OpenAI’s</strong></a><strong><a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Codex moves beyond the desktop</a></strong> <a class="header-anchor" href="#📱-openai-scodex-moves-beyond-the-desktop" aria-label="Permalink to &quot;📱****[**OpenAI’s**](https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**[Codex moves beyond the desktop](https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: OpenAI</p><p><strong>The Rundown:</strong> OpenAI just <a href="https://openai.com/index/work-with-codex-from-anywhere/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">rolled out</a> Codex in preview inside the ChatGPT iOS app across all plans, giving developers a way to track, manage, and act on long-running AI tasks from their phone as the company battles Anthropic for the coding tool market.</p><p><strong>The details:</strong></p><ul><li><p>Codex continues to run on a laptop or remote host, with users able to access live threads, code changes, approvals, plugins, and start new tasks via mobile.</p></li><li><p>OAI said the mobile system uses a “secure relay layer” that doesn’t expose the computer to the open internet, and syncs with other ChatGPT instances.</p></li><li><p>OAI seemed to point right at Anthropic in its blog, saying it’s “more than the ability to remotely control a single task or dispatch new tasks to your computer.”</p></li><li><p>Anthropic introduced <a href="https://code.claude.com/docs/en/remote-control?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Remote Control</a> in February and <a href="https://www.rundown.ai/articles/anthropic-claude-gets-remote-control?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Dispatch</a> in March, giving Claude limited mobile access and desktop accessibility on the go.</p></li></ul><p><strong>Why it matters:</strong> The days of users walking around with <a href="https://www.businessinsider.com/coders-keep-laptops-open-in-public-ai-agent-2026-5?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">open computers</a> to keep agents running may be coming to an end. Especially as models continue to improve at running for hours at a time, keeping things moving on the go is a major quality of life update that unshackles users from desks and computers.</p><h6 id="together-with-braintrust" tabindex="-1">TOGETHER WITH BRAINTRUST <a class="header-anchor" href="#together-with-braintrust" aria-label="Permalink to &quot;TOGETHER WITH BRAINTRUST&quot;">​</a></h6><h4 id="🚀-start-shipping-ai-products-like-the-leading-teams" tabindex="-1">🚀****<a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"><strong>Start shipping AI products like the leading teams</strong></a> <a class="header-anchor" href="#🚀-start-shipping-ai-products-like-the-leading-teams" aria-label="Permalink to &quot;🚀****[**Start shipping AI products like the leading teams**](https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15)&quot;">​</a></h4><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown</strong> : Braintrust is the end-to-end platform for evaluating, monitoring, and iterating on AI products. Teams at Notion, Vercel, and Stripe use it to catch regressions before users do, debug agent behavior across thousands of traces, and turn iterations from guesswork into a measurable, repeatable workflow.</p><p><strong>Using Braintrust, you can:</strong></p><ul><li><p>Eval prompts, models, and agents side-by-side</p></li><li><p>Trace every agent and application LLM call</p></li><li><p>Run evals against production traces</p></li></ul><p><a href="https://www.braintrust.dev/signup?utm_source=newsletter&amp;utm_medium=rundown&amp;utm_campaign=signup&amp;utm_content=primary_2026-05-15" target="_blank" rel="noreferrer">Sign up free</a>.</p><h6 id="openai-apple" tabindex="-1">OPENAI &amp; APPLE <a class="header-anchor" href="#openai-apple" aria-label="Permalink to &quot;OPENAI &amp; APPLE&quot;">​</a></h6><h4 id="💔-openai-apple-s-deteriorating-relationship" tabindex="-1">💔 <strong><a href="https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?srnd=phx-technology&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">OpenAI, Apple’s ‘deteriorating’ relationship</a></strong> <a class="header-anchor" href="#💔-openai-apple-s-deteriorating-relationship" aria-label="Permalink to &quot;💔 **[OpenAI, Apple’s ‘deteriorating’ relationship](https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?srnd=phx-technology&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> OpenAI is reportedly <a href="https://www.bloomberg.com/news/articles/2026-05-14/openai-apple-partnership-frays-setting-up-possible-legal-fight?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">considering</a> legal action against Apple over their 2024 ChatGPT-Siri deal, enlisting a law firm to explore options that may include a breach-of-contract notice due to the results of the “deteriorating” partnership.</p><p><strong>The details:</strong></p><ul><li><p>The two sides <a href="https://www.rundown.ai/articles/the-apple-intelligence-era-is-here?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">entered a deal</a> in 2024 during the initial Apple Intelligence launch, giving Siri the ability to call on ChatGPT for more complex queries.</p></li><li><p>OAI expected the deal to drive “billions” in paid ChatGPT signups, but internal data showed users favor the standalone app over Apple&#39;s limited integration.</p></li><li><p>The iPhone maker plans to open Siri to rival AI providers like Anthropic&#39;s Claude and Google Gemini in iOS 27, reportedly set to debut at WWDC on June 8.</p></li><li><p>Apple was also allegedly “fuming” over OAI poaching from its hardware teams, with OAI also emerging as a potential competitor through its Jony Ive deal.</p></li></ul><p><strong>Why it matters:</strong> Like everything else Apple Intelligence, the ChatGPT integration was a bust, and now yet another OAI relationship with a tech giant seems to be on thin ice. But with rumors of its <a href="https://www.rundown.ai/articles/openai-ai-phone-just-jumped-the-line?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">own phone</a> coming in 2027, there could be a big new rivalry in the AI hardware market — especially if the Siri relaunch doesn’t live up to expectations.</p><h6 id="ai-training-3" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-3" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="🎨-automate-marketing-assets-with-chatgpt-images-2-0" tabindex="-1">🎨 <strong><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Automate marketing assets with ChatGPT Images 2.0</a></strong> <a class="header-anchor" href="#🎨-automate-marketing-assets-with-chatgpt-images-2-0" aria-label="Permalink to &quot;🎨 **[Automate marketing assets with ChatGPT Images 2.0](https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to use Codex Desktop to build a ChatGPT Images 2.0 app that turns a marketing campaign and design brief into prompts, test images, and a review gallery.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a project folder and initialize git: mkdir gpt-image-review-app cd gpt-image-review-app git init. Open the folder in Codex Desktop</p></li><li><p>Ask Codex to build a local browser app for GPT Image 2.0, where you can enter a marketing brief, generate editable prompts, create test images, choose image dimensions, and review outputs with Keep, Reject, and Needs revision controls</p></li><li><p>After the build, add your OpenAI API key to the app’s .env file, run the app locally, and describe your campaign, design brief, and desired image formats</p></li><li><p>Click &quot;Generate Prompts,&quot; then click &quot;Generate Images to Test.&quot; Review the outputs with Keep, Reject, and Needs labels, then save the strongest results</p></li></ol><p><strong>Pro tip:</strong> Once the app works, use Codex Desktop Annotation Mode to click or drag over fixes for aspects like labels, spacing, states, controls, or layout.</p><h6 id="presented-by-nextsense-smartbuds" tabindex="-1">PRESENTED BY NEXTSENSE SMARTBUDS <a class="header-anchor" href="#presented-by-nextsense-smartbuds" aria-label="Permalink to &quot;PRESENTED BY NEXTSENSE SMARTBUDS&quot;">​</a></h6><h4 id="🧠-neuroscience-built-into-earbuds" tabindex="-1">🧠****<a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"><strong>Neuroscience, built into earbuds</strong></a> <a class="header-anchor" href="#🧠-neuroscience-built-into-earbuds" aria-label="Permalink to &quot;🧠****[**Neuroscience, built into earbuds**](https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)&quot;">​</a></h4><p><a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> NextSense Smartbuds use clinical-grade EEG sensors to detect your brainwaves in real time, and respond with audio that achieves your desired mental state, such as sleep, relaxation, or deep meditation. Track your mind as it shifts, experience deeper recovery, and explore a new interface to the brain.</p><p><strong>Smartbuds’ features include:</strong></p><ul><li><p>EEG sensors that monitor brain activity in real-time</p></li><li><p>Sounds that adapt to your brain to enhance wellbeing</p></li><li><p>Dynamic experiences to support sleep, meditation, and more</p></li></ul><p><a href="https://nextsense.io/pages/the-24-hour-smartbud?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Explore Smartbuds</a>.****</p><h6 id="anthropic-1" tabindex="-1">ANTHROPIC <a class="header-anchor" href="#anthropic-1" aria-label="Permalink to &quot;ANTHROPIC&quot;">​</a></h6><h4 id="💰-anthropic-angers-devs-with-new-agent-credit-split" tabindex="-1">💰 <strong><a href="https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Anthropic angers devs with new agent credit split</a></strong> <a class="header-anchor" href="#💰-anthropic-angers-devs-with-new-agent-credit-split" aria-label="Permalink to &quot;💰 **[Anthropic angers devs with new agent credit split](https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h4><p>Image source: Images 2.0 / The Rundown</p><p><strong>The Rundown:</strong> Anthropic <a href="https://support.claude.com/en/articles/15036540-use-the-claude-agent-sdk-with-your-claude-plan?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">announced</a> a policy that will split Claude&#39;s agent usage into a monthly credit pool, restoring support for third-party agentic tools but angering power users in the process by walling them off from normal subscription limits.</p><p><strong>The details:</strong></p><ul><li><p>Starting June 15, Agent SDK and claude -p no longer draw from subscription limits, and will be solely used towards Claude Code, Cowork, and chat.</p></li><li><p>Pro users will get $20/month in agentic credits, Max 5x gets $100, and Max 20x gets $200 — with credits resetting after each billing cycle and not rolling over.</p></li><li><p>The move reverses Anthropic&#39;s April ban on third-party agents like OpenClaw, but removes the subsidy that gave its plans significantly more value in compute.</p></li><li><p>The move resulted in backlash from power users, with T3 founder Theo Browne and hundreds of others <a href="https://x.com/theo/status/2054734057368621176?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">publicly</a> cancelling their subscriptions.</p></li></ul><p><strong>Why it matters:</strong> Agents’ ability to burn through tokens has broken the AI subscription model, but Anthropic has also not done itself any favors with the dev community of late. These tiny token allocations feel even worse than blocking agents outright — and it comes right as OAI continues to up Codex limits to encourage switching.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-3" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-3" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><ul><li><p>🗣️ <a href="https://www.unwrap.ai/product-product-operations-ai-product?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Unwrap Customer Intelligence</a> - Get AI-driven insights from your unstructured customer feedback to build your product roadmap*</p></li><li><p>🎨 <a href="https://www.rundown.ai/tools/recraft-v4-1?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Recraft V4.1</a> - Image AI with improved photorealism, illustration, and more</p></li><li><p>⚙️ <a href="https://www.notion.com/blog/introducing-developer-platform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Notion Developer Platform</a> - Open platform to build directly on Notion</p></li><li><p>🔬 <a href="https://www.rundown.ai/tools/autoscientist?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">AutoScientist</a> - Adaption&#39;s new tool for automating AI model training</p></li></ul><p><em>*Sponsored Listing</em></p><h3 id="📰-everything-else-in-ai-today-3" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-3" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><p><strong>xAI</strong> <a href="https://x.ai/cli?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">released</a> Grok Build, an initial beta version of the company’s agentic CLI, currently limited to SuperGrok Heavy subscribers.</p><p><strong>U.S. AI chipmaker Cerebras</strong> officially <a href="https://www.nbcnews.com/business/business-news/ai-chipmaker-cerebras-soars-90-years-biggest-ipo-far-rcna345128?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">went public</a>, with its stock more than doubling from its open just hours into trading and marking the biggest IPO of the year so far.</p><p><strong>Higgsfield AI</strong><a href="https://x.com/higgsfield_ai/status/2054989169446023181?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">launched</a> Supercomputer, a cloud AI agent that can complete full creative and marketing tasks end-to-end while orchestrating multiple models and tools.</p><p><strong>Runway</strong> <a href="https://x.com/runwayml/status/2054593196773011929?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">introduced</a> Agent, a new agentic assistant on its video platform that collaborates with users through their creative workflows.</p><p><strong>Dating app Bumble</strong> is <a href="https://www.axios.com/2026/05/11/bumble-reset-gen-z-dating-apps?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">phasing out</a> its swipe feature to instead rely on a new AI dating assistant called ‘Bee’ for matchmaking, profile optimization, and more.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-3" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-3" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Nicolas D.</strong> in Quebec:</p><p>For months, Claude has been my personal coach — tracking my habits, building my workouts, adjusting my plans. Every Sunday, I feed Claude a log of the past week — sessions, wellbeing, and soreness — and it generates next week&#39;s program.</p><p>Then it hit me: my habits are tied to long-term goals. So why not manage them like projects?</p><p>I&#39;ve worked in project management for years. I built a Gantt chart linked directly to my habit-tracking software. The tracker now acts as a time-punch system — every session logged becomes a task completed on the timeline. I&#39;m running my life&#39;s projects the way I run work projects. Best decision I&#39;ve made for staying consistent.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-3" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-3" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/the-enterprise-shift-openai-saw-coming?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">The enterprise shift OpenAI saw coming</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/venmo-finally-kills-its-most-criticized-feature?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Venmo kills its most criticized feature</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meet-unitree-giant-new-mech?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Meet Unitree’s giant new mech</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">Automate marketing assets with Image</a><a href="https://app.therundown.ai/guides/automate-marketing-assets-with-chatgpt-image-20?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-takes-codex-mobile" target="_blank" rel="noreferrer">s 2.0</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr><h2 id="the-enterprise-shift-openai-saw-coming" tabindex="-1"><a href="https://www.therundown.ai/p/the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">The enterprise shift OpenAI saw coming</a> <a class="header-anchor" href="#the-enterprise-shift-openai-saw-coming" aria-label="Permalink to &quot;[The enterprise shift OpenAI saw coming](https://www.therundown.ai/p/the-enterprise-shift-openai-saw-coming)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-14</em></p><p><strong><a href="https://rss.beehiiv.com/feeds/" target="_blank" rel="noreferrer">Read Online</a></strong> | <strong><a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Sign Up</a></strong> | <strong><a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Advertise</a></strong></p><p><a href="https://cloud.google.com/products/gemini-enterprise-agent-platform?utm_source=fnf&amp;utm_medium=newsletter&amp;utm_campaign=google-cloud-may&amp;utm_term=rundown&amp;utm_content=multi-agent-code-lab" target="_blank" rel="noreferrer"></a></p><p><strong>Good morning, AI enthusiasts.</strong> Two months ago, OpenAI&#39;s Fidji Simo told staff the company was in a &quot;code red&quot; over Anthropic&#39;s enterprise rise. New spend data says the leaderboard has actually flipped.</p><p>Ramp’s latest AI Index just showed Anthropic leading adoption among its paid business users for the first time, a 4x adoption surge since 2025 that may tell the story of why OpenAI has been drastically shifting its priorities throughout 2026.</p><p><em>P.S. — Our next live workshop, &#39;Finally Getting AI to Do Real Work&#39;, is today at 2 PM EST. Join for a breakdown of how AI actually works in 2026 and the context habits power users layer on top to get reliable output from any model.</em><a href="https://app.therundown.ai/live/finally-getting-ai-to-do-real-work?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer"><em>RSVP here</em></a> <em>.</em></p><hr><p><strong>In today’s AI rundown:</strong></p><ul><li><p>Anthropic seizes OpenAI&#39;s business AI lead</p></li><li><p>Amazon doubles down on Alexa+ for shopping</p></li><li><p>Create content with Claude Code and Higgsfield</p></li><li><p>Adaption automates AI training with AutoScientist</p></li><li><p>4 new AI tools, community workflows, and more</p></li></ul><p><strong>LATEST DEVELOPMENTS</strong></p><h6 id="anthropic-openai" tabindex="-1">ANTHROPIC &amp; OPENAI <a class="header-anchor" href="#anthropic-openai" aria-label="Permalink to &quot;ANTHROPIC &amp; OPENAI&quot;">​</a></h6><h4 id="🏢-anthropic-seizes-openai-s-business-ai-lead" tabindex="-1">🏢 <strong><a href="https://ramp.com/leading-indicators/ai-index-may-2026?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Anthropic seizes OpenAI&#39;s business AI lead</a></strong> <a class="header-anchor" href="#🏢-anthropic-seizes-openai-s-business-ai-lead" aria-label="Permalink to &quot;🏢 **[Anthropic seizes OpenAI&#39;s business AI lead](https://ramp.com/leading-indicators/ai-index-may-2026?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h4><p>Image source: Ramp</p><p><strong>The Rundown:</strong> Fintech firm**** Ramp just <a href="https://ramp.com/leading-indicators/ai-index-may-2026?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">published</a> its latest AI Index, showing Anthropic taking the paid business-adoption lead from OpenAI for the first time, an enterprise surge that has quadrupled its usage over the past year while OpenAI has leveled off.</p><p><strong>The details:</strong></p><ul><li><p>Ramp tracks corporate card and invoice payments from 50K+ U.S. businesses, making this a spend signal, not full market share.</p></li><li><p>Anthropic rose 3.8% in April to 34.4% of adoption, while OpenAI fell 2.9% to 32.3% as overall AI use continued to climb to 50.6%.</p></li><li><p>Claude Code anchored much of the swing, with Anthropic expanding from technical teams into finance, legal, and research workflows.</p></li><li><p>Ramp highlighted several risks facing Anthropic despite the trend, including recent Claude outages and increasing costs compared to OAI and open-source.</p></li></ul><p><strong>Why it matters:</strong> OpenAI is not suddenly cooked, with Ramp not tracking some large enterprise deals and ChatGPT remaining the bigger consumer brand**.** The yearly trend speaks louder, and was likely the same type of chart that caused OAI’s Fidji Simo-led <a href="https://www.rundown.ai/articles/simo-sounds-alarm-on-openai-side-quests?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">pivot</a>, which has become evident from recent Codex and other enterprise pushes.</p><h6 id="together-with-google-cloud" tabindex="-1">TOGETHER WITH GOOGLE CLOUD <a class="header-anchor" href="#together-with-google-cloud" aria-label="Permalink to &quot;TOGETHER WITH GOOGLE CLOUD&quot;">​</a></h6><h4 id="🤖-build-a-multi-agent-ai-system" tabindex="-1">🤖****<a href="https://cloud.google.com/products/gemini-enterprise-agent-platform?utm_source=fnf&amp;utm_medium=newsletter&amp;utm_campaign=google-cloud-may&amp;utm_term=rundown&amp;utm_content=multi-agent-code-lab" target="_blank" rel="noreferrer"><strong>Build a Multi-Agent AI System</strong></a> <a class="header-anchor" href="#🤖-build-a-multi-agent-ai-system" aria-label="Permalink to &quot;🤖****[**Build a Multi-Agent AI System**](https://cloud.google.com/products/gemini-enterprise-agent-platform?utm_source=fnf&amp;utm_medium=newsletter&amp;utm_campaign=google-cloud-may&amp;utm_term=rundown&amp;utm_content=multi-agent-code-lab)&quot;">​</a></h4><p><a href="https://cloud.google.com/products/gemini-enterprise-agent-platform?utm_source=fnf&amp;utm_medium=newsletter&amp;utm_campaign=google-cloud-may&amp;utm_term=rundown&amp;utm_content=multi-agent-code-lab" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> Scale your AI operations with the Gemini Enterprise Agent Platform, Google’s new evolution for building, governing, and optimizing AI agents. Using the open-source Agent Development Kit (ADK), this hands-on codelab teaches you to orchestrate specialized agents like Researchers and Judges into self-correcting workflows that solve complex problems at enterprise scale.</p><p><strong>In this codelab, you will:</strong></p><ul><li><p>Construct self-correcting AI feedback loops.</p></li><li><p>Orchestrate task hand-offs between specialized agents.</p></li><li><p>Deploy production-ready workflows to Google Cloud Run.</p></li></ul><p><a href="https://codelabs.developers.google.com/codelabs/production-ready-ai-roadshow/1-building-a-multi-agent-system/building-a-multi-agent-system?utm_source=fnf&amp;utm_medium=newsletter&amp;utm_campaign=google-cloud-may&amp;utm_term=rundown&amp;utm_content=multi-agent-code-lab" target="_blank" rel="noreferrer">Build and deploy your first Multi-Agent system with Google</a>.</p><h6 id="amazon" tabindex="-1">AMAZON <a class="header-anchor" href="#amazon" aria-label="Permalink to &quot;AMAZON&quot;">​</a></h6><h4 id="🛒-amazon-doubles-down-on-alexa-for-shopping" tabindex="-1">🛒 <strong><a href="https://www.aboutamazon.com/news/retail/alexa-for-shopping-ai-assistant?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Amazon doubles down on Alexa+ for shopping</a></strong> <a class="header-anchor" href="#🛒-amazon-doubles-down-on-alexa-for-shopping" aria-label="Permalink to &quot;🛒 **[Amazon doubles down on Alexa+ for shopping](https://www.aboutamazon.com/news/retail/alexa-for-shopping-ai-assistant?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h4><p>Image source: Amazon</p><p><strong>The Rundown:</strong> Amazon <a href="https://www.aboutamazon.com/news/retail/alexa-for-shopping-ai-assistant?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">folded</a> its standalone shopping chatbot ‘Rufus’ inside &quot;Alexa for Shopping&quot;, a new agent that takes over Amazon search and follows shoppers across devices with a shared memory of purchases, preferences, and prior chats.</p><p><strong>The details:</strong></p><ul><li><p>Rufus drew 300M+ users in 2025 while still in beta, with its product knowledge and shopping history now feeding Alexa for Shopping answers.</p></li><li><p>Amazon says the new assistant draws on catalog data, reviews, delivery timing, past purchases, and Alexa conversations for information.</p></li><li><p>Alexa can now field questions in the search bar, run side-by-side comparisons, track pricing, and Auto-Buy items when prices hit a target.</p></li><li><p>A new Buy for Me handles checkouts on non-Amazon stores, with Scheduled Actions able to automatically restock products on a cadence.</p></li></ul><p><strong>Why it matters:</strong> RIP to Rufus, but consolidating under one Alexa AI brand feels like a better play, and the sheer amount of customer history Amazon has gives its agent quite the moat to work with. But with a consumer base that is already moving to other AI platforms for their agentic shopping needs, will Alexa play nice and integrate with them?</p><h6 id="ai-training-4" tabindex="-1">AI TRAINING <a class="header-anchor" href="#ai-training-4" aria-label="Permalink to &quot;AI TRAINING&quot;">​</a></h6><h4 id="📸-create-content-with-claude-code-and-higgsfield" tabindex="-1">📸 <strong><a href="https://app.therundown.ai/guides/turn-prompts-into-content-with-claude-code-higgsfield?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Create content with Claude Code and Higgsfield</a></strong> <a class="header-anchor" href="#📸-create-content-with-claude-code-and-higgsfield" aria-label="Permalink to &quot;📸 **[Create content with Claude Code and Higgsfield](https://app.therundown.ai/guides/turn-prompts-into-content-with-claude-code-higgsfield?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h4><p><a href="https://app.therundown.ai/guides/turn-prompts-into-content-with-claude-code-higgsfield?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> In this guide, you will learn how to connect Higgsfield to Claude Code with the Higgsfield CLI, then use Claude Code to send one image prompt to several AI image models at once.</p><p><strong>Step-by-step:</strong></p><ol><li><p>Create a new project folder, install Higgsfield CLI (npm install -g @higgsfield/cli), authenticate (higgsfield auth login), and add Higgsfield skill (npx skills add higgsfield-ai/skills) for Claude Code</p></li><li><p>Open Claude Code in the same folder and ask it to inspect <a href="https://higgsfield.ai/cli?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">higgsfield.ai/cli</a>, verify the installation, and list available image models</p></li><li><p>Give Claude Code an image prompt and tell it to run it across six models, save outputs into a higgsfield-model-test folder, and generate a <a href="https://comparison.md?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">comparison.md</a> file with notes for each result</p></li><li><p>Pick the best direction, then ask Claude Code to refine the winning prompt or run one more comparison</p></li></ol><p><strong>Pro tip:</strong> If setup gets confusing, ask Claude Code to check Node/npm and give a walkthrough. Higgsfield also supports video, so you can also try this for short clips.</p><h6 id="presented-by-stripe" tabindex="-1">PRESENTED BY STRIPE <a class="header-anchor" href="#presented-by-stripe" aria-label="Permalink to &quot;PRESENTED BY STRIPE&quot;">​</a></h6><h4 id="💰-pricing-ai-lessons-from-leading-ai-companies" tabindex="-1">💰 <strong><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=T6lwAd3CQk4mKC0i8HQG1TAxr" target="_blank" rel="noreferrer">Pricing AI: Lessons from leading AI companies</a></strong> <a class="header-anchor" href="#💰-pricing-ai-lessons-from-leading-ai-companies" aria-label="Permalink to &quot;💰 **[Pricing AI: Lessons from leading AI companies](https://stripe.com/lp/pricing-ai-products?utm_campaign=T6lwAd3CQk4mKC0i8HQG1TAxr)**&quot;">​</a></h4><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=T6lwAd3CQk4mKC0i8HQG1TAxr" target="_blank" rel="noreferrer"></a></p><p><strong>The Rundown:</strong> AI companies are hitting revenue milestones faster than ever—but figuring out how to monetize AI products is still one of the hardest problems founders face. Stripe interviewed teams at Anthropic, Vercel, Clay, and more to build a five-step pricing framework for AI products.</p><p><strong>Download the guide to learn best practices for how to:</strong></p><ul><li><p>Pick the right pricing model</p></li><li><p>Prevent billing surprises</p></li><li><p>Refine your pricing over time</p></li></ul><p><a href="https://stripe.com/lp/pricing-ai-products?utm_campaign=T6lwAd3CQk4mKC0i8HQG1TAxr" target="_blank" rel="noreferrer">Get the framework</a>.****</p><h6 id="adaption" tabindex="-1">ADAPTION <a class="header-anchor" href="#adaption" aria-label="Permalink to &quot;ADAPTION&quot;">​</a></h6><h4 id="🔬-adaption-automates-ai-training-with-autoscientist" tabindex="-1">🔬 <strong><a href="https://www.adaptionlabs.ai/blog/autoscientist?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Adaption automates AI training with AutoScientist</a></strong> <a class="header-anchor" href="#🔬-adaption-automates-ai-training-with-autoscientist" aria-label="Permalink to &quot;🔬 **[Adaption automates AI training with AutoScientist](https://www.adaptionlabs.ai/blog/autoscientist?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h4><p>Image source: Adaption</p><p><strong>The Rundown:</strong> Adaption, the AI startup from ex-Cohere VP of Research Sara Hooker, just <a href="https://www.adaptionlabs.ai/blog/autoscientist?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">introduced</a> AutoScientist, a new system that automatically customizes AI models for specific jobs by adjusting both what the model learns from and how it learns.</p><p><strong>The details:</strong></p><ul><li><p>AutoScientist tests different training data and settings, then iterates until the model meets the user&#39;s goal.</p></li><li><p>In internal tests, AutoScientist outperformed its own expert-tuned models by 35% on average, with success rates jumping from 48% to 64%.</p></li><li><p>Results held across multiple AI models, a wide range of dataset sizes, and 8 varied industries, including finance, legal, and medical domains.</p></li><li><p>Adaptive’s initial Adaptive Data <a href="https://www.adaptionlabs.ai/blog/adaption-launches-adaptive-data-beta?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">release</a> in February aimed at increasing the quality of datasets, with Autoscientist now moving toward customizing models.</p></li></ul><p><strong>Why it matters:</strong> A few thousand people in the world know how to properly train and fine-tune a frontier model, and nearly all of them work at the same handful of labs. If a tool like Autoscientist can start to automate that expertise, models customized for individual businesses and use cases may become a lot more practical to create.</p><p><strong>QUICK HITS</strong></p><h3 id="🛠️-trending-ai-tools-4" tabindex="-1">🛠️ <strong><a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Trending AI Tools</a></strong> <a class="header-anchor" href="#🛠️-trending-ai-tools-4" aria-label="Permalink to &quot;🛠️ **[Trending AI Tools](https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h3><ul><li><p>🛍️ <a href="https://www.rundown.ai/tools/alexa-for-shopping?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Alexa for Shopping</a> - Shopping agent for Q&amp;A, price tracking, and auto-buy</p></li><li><p>💻 <a href="http://www.rundown.ai/tools/higgsfield-supercomputer?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Higgsfield Supercomputer</a> - Cloud AI agent with tools, memory, and more</p></li><li><p>🔐 <a href="https://www.rundown.ai/tools/incognito-chat?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Incognito Chat</a> - New way to have private chats with Meta AI on WhatsApp</p></li><li><p>🏪 <a href="http://www.rundown.ai/tools/claude-for-small-business?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Claude for Small Business</a> - New tools for payroll, invoices, and campaigns</p></li></ul><h3 id="📰-everything-else-in-ai-today-4" tabindex="-1">📰 <strong><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Everything else in AI today</a></strong> <a class="header-anchor" href="#📰-everything-else-in-ai-today-4" aria-label="Permalink to &quot;📰 **[Everything else in AI today](https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h3><p><strong>Nvidia</strong><a href="https://x.com/TheRundownAI/status/2054576718283722854?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">became</a> the first company to hit a $5.5T market cap, coming as CEO Jensen Huang arrived in China to join U.S. President Donald Trump in meetings with Xi Jinping.</p><p><strong>Sam Altman</strong> <a href="https://techcrunch.com/2026/05/12/musk-mulled-handing-openai-to-his-children-altman-testifies/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">testified</a> in the Elon Musk vs. OpenAI legal battle that Musk’s “specific plans on safety” made him worry, and proposed passing the company to his children.</p><p><strong>David Silver’s Ineffable Intelligence and Nvidia</strong> <a href="https://blogs.nvidia.com/blog/ineffable-intelligence-reinforcement-learning-infrastructure/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">announced</a> a partnership to build training pipelines for RL agents, with early work targeting Nvidia&#39;s Vera Rubin hardware.</p><p><strong>Microsoft</strong> <a href="https://www.microsoft.com/en-us/security/blog/2026/05/12/defense-at-ai-speed-microsofts-new-multi-model-agentic-security-system-tops-leading-industry-benchmark/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">introduced</a> MDASH, an AI security harness that chains 100+ specialized agents to hunt for software bugs, with the system catching 16 flaws across Windows.</p><p><strong>UK&#39;s AI Safety Institute</strong> <a href="https://www.aisi.gov.uk/blog/how-fast-is-autonomous-ai-cyber-capability-advancing?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">said</a> that AI’s ability to complete cyberattacks is doubling every few months, with Mythos Preview and GPT-5.5 finishing its simulated breaches.</p><p><strong>COMMUNITY</strong></p><h3 id="🤝-community-ai-workflows-4" tabindex="-1">🤝 <strong><a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Community AI workflows</a></strong> <a class="header-anchor" href="#🤝-community-ai-workflows-4" aria-label="Permalink to &quot;🤝 **[Community AI workflows](https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h3><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader <strong>Rod R.</strong> in Elizabethtown, KY:</p><p>&quot;I am an avid cyclist. I turned 61 years old this year, but I am still participating in multi-day cycling events. I needed advice on the type of riding I should be doing to prepare, and I thought I could benefit from a coach, but I can’t afford one. Then it occurred to me to try ChatGPT.</p><p>That has worked out tremendously! We had a “conversation” about my goals, medical history, current fitness, event dates, etc. I have been following a training plan for about 6 weeks now.</p><p>ChatGPT continues to coach me as I report on each ride, helps me restructure the plan when life requires me to modify it, and also remembers things we have already discussed. I love how this has helped me to prepare, and I have peace of mind from knowing what I should be doing each day. Today is a rest day! 😊&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">here</a>.</p><h3 id="🎓-highlights-news-guides-events-4" tabindex="-1"><strong>🎓</strong>**<a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Highlights: News, Guides&amp; Events</a>** <a class="header-anchor" href="#🎓-highlights-news-guides-events-4" aria-label="Permalink to &quot;**🎓****[Highlights: News, Guides&amp; Events](https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming)**&quot;">​</a></h3><ul><li><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/android-enters-its-gemini-intelligence-era?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Android enters its Gemini Intelligence era</a></p></li><li><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/venmo-finally-kills-its-most-criticized-feature?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Venmo finally kills its most criticized feature</a></p></li><li><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/figure-robots-make-a-bed-together?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Figure’s robots make a bed together</a></p></li><li><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/turn-prompts-into-content-with-claude-code-higgsfield?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Create content with Claude Code and Higgsfield</a></p></li><li><p>RSVP to our next workshop @ 2 PM EST today: <a href="https://app.therundown.ai/live/finally-getting-ai-to-do-real-work?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-enterprise-shift-openai-saw-coming" target="_blank" rel="noreferrer">Getting AI to do real work</a></p></li></ul><p>See you soon,</p><p><em>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</em></p><hr>',379)])])}const c=t(o,[["render",i]]);export{h as __pageData,c as default};
